// ⚙️ CONFIG — associe chaque maison à sa femme de ménage (nom + téléphone).
// Les clés doivent correspondre EXACTEMENT au nom de la propriété dans Lodgify.
const CLEANERS = {
  "Gite Royan 6 pers + jaccuzi + proche plage": { nom: "Marie", tel: "+33600000001" },
  "Maison d'architecte avec piscine près de bordeaux": { nom: "Sophie", tel: "+33600000002" },
};

const FR = ['janv.','févr.','mars','avr.','mai','juin','juil.','août','sept.','oct.','nov.','déc.'];
function jour(iso){ const [y,m,d]=iso.split('-'); return `${+d} ${FR[+m-1]}`; }

const resp = $input.first().json;
const props = resp.properties || [];
const today = new Date();
const limit = new Date(today); limit.setDate(limit.getDate()+30);
const limitIso = limit.toISOString().slice(0,10);

const out = [];
for (const p of props){
  const cleaner = CLEANERS[p.name];
  if (!cleaner) continue; // maison sans femme de ménage assignée → ignorée
  const list = (p.turnovers||[]).filter(t => t.checkout <= limitIso);
  if (!list.length) continue;

  const lignes = list.map(t => {
    if (t.sameDay) return `- ${jour(t.checkout)} : ⚠️ ménage EXPRESS (arrivée le jour même)`;
    if (t.gapDays!==null && t.gapDays<=2) return `- ${jour(t.checkout)} : ménage sous ${t.gapDays} j (arrivée le ${jour(t.nextCheckin)})`;
    if (t.nextCheckin) return `- ${jour(t.checkout)} : prochaine arrivée le ${jour(t.nextCheckin)}`;
    return `- ${jour(t.checkout)} : ménage à planifier`;
  }).join('\n');

  const message = `Bonjour ${cleaner.nom},\nVoici les ménages à prévoir pour "${p.name}" (30 prochains jours) :\n${lignes}\n\nMerci et bonne semaine !`;
  out.push({ json: { to: cleaner.tel, message } });
}

return out;
